diff:
diff --git a/Dapper/DefaultTypeMap.cs b/Dapper/DefaultTypeMap.cs
index 9802974..213c599 100644
--- a/Dapper/DefaultTypeMap.cs
+++ b/Dapper/DefaultTypeMap.cs
@@ -74,35 +74,37 @@ internal static List<FieldInfo> GetSettableFields(Type t)
                 if (ctorParameters.Length == 0)
                     return ctor;

-                if (ctorParameters.Length != types.Length)
+                if (ctorParameters.Length != names.Length)
                     continue;

-                int i = 0;
-                for (; i < ctorParameters.Length; i++)
+                // Match each constructor parameter to a column by name (case-insensitive),
+                // regardless of column order.
+                bool allMatch = true;
+                for (int i = 0; i < ctorParameters.Length; i++)
                 {
-                    if (EqualsCI(ctorParameters[i].Name, names[i]))
-                    { } // exact match
-                    else if (MatchNamesWithUnderscores && EqualsCIU(ctorParameters[i].Name, names[i]))
-                    { } // match after applying underscores
-                    else
+                    // Find the column index whose name matches this parameter
+                    int colIndex = -1;
+                    for (int j = 0; j < names.Length; j++)
                     {
-                        // not a name match
-                        break;
+                        if (EqualsCI(ctorParameters[i].Name, names[j]))
+                        { colIndex = j; break; }
+                        else if (MatchNamesWithUnderscores && EqualsCIU(ctorParameters[i].Name, names[j]))
+                        { colIndex = j; break; }
                     }
+                    if (colIndex < 0) { allMatch = false; break; }

-                    if (types[i] == typeof(byte[]) && ctorParameters[i].ParameterType.FullName == SqlMapper.LinqBinary)
+                    if (types[colIndex] == typeof(byte[]) && ctorParameters[i].ParameterType.FullName == SqlMapper.LinqBinary)
                         continue;
                     var unboxedType = Nullable.GetUnderlyingType(ctorParameters[i].ParameterType) ?? ctorParameters[i].ParameterType;
-                    if ((unboxedType != types[i] && !SqlMapper.HasTypeHandler(unboxedType))
-                        && !(unboxedType.IsEnum && Enum.GetUnderlyingType(unboxedType) == types[i])
-                        && !(unboxedType == typeof(char) && types[i] == typeof(string))
-                        && !(unboxedType.IsEnum && types[i] == typeof(string)))
+                    if ((unboxedType != types[colIndex] && !SqlMapper.HasTypeHandler(unboxedType))
+                        && !(unboxedType.IsEnum && Enum.GetUnderlyingType(unboxedType) == types[colIndex])
+                        && !(unboxedType == typeof(char) && types[colIndex] == typeof(string))
+                        && !(unboxedType.IsEnum && types[colIndex] == typeof(string)))
                     {
-                        break;
+                        allMatch = false; break;
                     }
                 }
-
-                if (i == ctorParameters.Length)
+                if (allMatch)
                     return ctor;
             }
